def sha256_file(path: str) -> str:
    h = hashlib.sha256()
    with open(path, "rb") as f:
        for chunk in iter(lambda: f.read(1024 * 1024), b""):
            h.update(chunk)
    return h.hexdigest()


def download_url(url: str, dst_path: str, timeout: int = 60) -> str:
    os.makedirs(os.path.dirname(dst_path), exist_ok=True)

    def _progress(block_num, block_size, total_size):
        if total_size <= 0:
            return
        downloaded = block_num * block_size
        pct = min(100.0, 100.0 * downloaded / total_size)
        sys.stderr.write(f"\rDownloading: {pct:6.2f}%")
        sys.stderr.flush()

    req = urllib.request.Request(url, headers={"User-Agent": "python-transfer-learning-downloader/1.0"})
    with urllib.request.urlopen(req, timeout=timeout) as r:
        total = r.length if hasattr(r, "length") else None
    urllib.request.urlretrieve(url, dst_path, reporthook=_progress)
    sys.stderr.write("\n")
    return dst_path


def atomic_download(url: str, cache_dir: str, filename: Optional[str] = None) -> str:
    os.makedirs(cache_dir, exist_ok=True)
    if filename is None:
        base = os.path.basename(url.split("?")[0]) or "checkpoint.pt"
        filename = base
    final_path = os.path.join(cache_dir, filename)

    if os.path.exists(final_path) and os.path.getsize(final_path) > 0:
        return final_path

    fd, tmp_path = tempfile.mkstemp(prefix="dl_", suffix=".tmp", dir=cache_dir)
    os.close(fd)
    try:
        download_url(url, tmp_path)
        os.replace(tmp_path, final_path)
    finally:
        if os.path.exists(tmp_path):
            try:
                os.remove(tmp_path)
            except OSError:
                pass
    return final_path


def build_model(arch: str, num_classes: int, pretrained: bool = False) -> nn.Module:
    arch = arch.lower()
    if arch in ("resnet18", "resnet-18"):
        m = models.resnet18(weights=models.ResNet18_Weights.DEFAULT if pretrained else None)
        m.fc = nn.Linear(m.fc.in_features, num_classes)
        return m
    if arch in ("resnet50", "resnet-50"):
        m = models.resnet50(weights=models.ResNet50_Weights.DEFAULT if pretrained else None)
        m.fc = nn.Linear(m.fc.in_features, num_classes)
        return m
    if arch in ("mobilenet_v3_small", "mobilenetv3small", "mobilenet-v3-small"):
        m = models.mobilenet_v3_small(weights=models.MobileNet_V3_Small_Weights.DEFAULT if pretrained else None)
        m.classifier[-1] = nn.Linear(m.classifier[-1].in_features, num_classes)
        return m
    if arch in ("mobilenet_v3_large", "mobilenetv3large", "mobilenet-v3-large"):
        m = models.mobilenet_v3_large(weights=models.MobileNet_V3_Large_Weights.DEFAULT if pretrained else None)
        m.classifier[-1] = nn.Linear(m.classifier[-1].in_features, num_classes)
        return m
    if arch in ("vit_b_16", "vitb16", "vit-b-16"):
        m = models.vit_b_16(weights=models.ViT_B_16_Weights.DEFAULT if pretrained else None)
        m.heads.head = nn.Linear(m.heads.head.in_features, num_classes)
        return m
    raise ValueError(f"Unsupported arch: {arch}")


def infer_num_classes_from_folder(root: str) -> int:
    for split in ("train", "training", "images"):
        p = os.path.join(root, split)
        if os.path.isdir(p):
            root = p
            break
    classes = [d for d in os.listdir(root) if os.path.isdir(os.path.join(root, d))]
    if not classes:
        raise ValueError(f"Could not infer classes from folder: {root}")
    return len(classes)


def get_dataloaders(
    data_dir: str,
    image_size: int,
    batch_size: int,
    val_split: float,
    num_workers: int,
    seed: int,
) -> Tuple[DataLoader, DataLoader, int]:
    train_tfms = transforms.Compose(
        [
            transforms.Resize((image_size, image_size)),
            transforms.RandomHorizontalFlip(),
            transforms.ToTensor(),
            transforms.Normalize(mean=(0.485, 0.456, 0.406), std=(0.229, 0.224, 0.225)),
        ]
    )
    val_tfms = transforms.Compose(
        [
            transforms.Resize((image_size, image_size)),
            transforms.ToTensor(),
            transforms.Normalize(mean=(0.485, 0.456, 0.406), std=(0.229, 0.224, 0.225)),
        ]
    )

    train_root = os.path.join(data_dir, "train")
    val_root = os.path.join(data_dir, "val")
    if os.path.isdir(train_root):
        train_ds = datasets.ImageFolder(train_root, transform=train_tfms)
        if os.path.isdir(val_root):
            val_ds = datasets.ImageFolder(val_root, transform=val_tfms)
        else:
            n = len(train_ds)
            n_val = int(round(n * val_split))
            n_train = n - n_val
            g = torch.Generator().manual_seed(seed)
            train_ds, val_ds = random_split(train_ds, [n_train, n_val], generator=g)
            train_ds.dataset.transform = train_tfms
            val_ds.dataset.transform = val_tfms
    else:
        full_ds = datasets.ImageFolder(data_dir, transform=train_tfms)
        n = len(full_ds)
        n_val = int(round(n * val_split))
        n_train = n - n_val
        g = torch.Generator().manual_seed(seed)
        train_ds, val_ds = random_split(full_ds, [n_train, n_val], generator=g)
        train_ds.dataset.transform = train_tfms
        val_ds.dataset.transform = val_tfms

    num_classes = len(getattr(train_ds, "classes", getattr(getattr(train_ds, "dataset", None), "classes", [])))
    if not num_classes:
        num_classes = infer_num_classes_from_folder(train_root if os.path.isdir(train_root) else data_dir)

    train_loader = DataLoader(train_ds, batch_size=batch_size, shuffle=True, num_workers=num_workers, pin_memory=True)
    val_loader = DataLoader(val_ds, batch_size=batch_size, shuffle=False, num_workers=num_workers, pin_memory=True)
    return train_loader, val_loader, num_classes


def load_checkpoint_from_url(
    url: str,
    cache_dir: str,
    map_location: str = "cpu",
    expected_sha256: Optional[str] = None,
    filename: Optional[str] = None,
) -> Tuple[Dict[str, Any], str]:
    ckpt_path = atomic_download(url, cache_dir=cache_dir, filename=filename)
    if expected_sha256:
        actual = sha256_file(ckpt_path)
        if actual.lower() != expected_sha256.lower():
            raise ValueError(f"SHA256 mismatch for {ckpt_path}: expected {expected_sha256}, got {actual}")
    obj = torch.load(ckpt_path, map_location=map_location)
    if not isinstance(obj, dict):
        obj = {"state_dict": obj}
    return obj, ckpt_path


def extract_state_dict(ckpt: Dict[str, Any]) -> Dict[str, torch.Tensor]:
    for k in ("state_dict", "model", "model_state", "model_state_dict", "net", "network", "weights"):
        if k in ckpt and isinstance(ckpt[k], dict):
            sd = ckpt[k]
            break
    else:
        sd = {k: v for k, v in ckpt.items() if isinstance(v, torch.Tensor)}
        if not sd:
            raise ValueError("Could not find a state_dict in checkpoint dict.")
    cleaned = {}
    for k, v in sd.items():
        nk = k
        if nk.startswith("module."):
            nk = nk[len("module.") :]
        cleaned[nk] = v
    return cleaned


def set_trainable(model: nn.Module, freeze_backbone: bool) -> None:
    if not freeze_backbone:
        for p in model.parameters():
            p.requires_grad = True
        return
    for p in model.parameters():
        p.requires_grad = False

    head_candidates = []
    if hasattr(model, "fc") and isinstance(model.fc, nn.Module):
        head_candidates.append(model.fc)
    if hasattr(model, "classifier") and isinstance(model.classifier, nn.Module):
        head_candidates.append(model.classifier)
    if hasattr(model, "heads") and isinstance(getattr(model.heads, "head", None), nn.Module):
        head_candidates.append(model.heads)

    if not head_candidates:
        for p in model.parameters():
            p.requires_grad = True
        return

    for head in head_candidates:
        for p in head.parameters():
            p.requires_grad = True


@torch.no_grad()
def evaluate(model: nn.Module, loader: DataLoader, device: torch.device) -> Tuple[float, float]:
    model.eval()
    criterion = nn.CrossEntropyLoss()
    total_loss = 0.0
    correct = 0
    total = 0
    for x, y in loader:
        x = x.to(device, non_blocking=True)
        y = y.to(device, non_blocking=True)
        logits = model(x)
        loss = criterion(logits, y)
        total_loss += float(loss.item()) * x.size(0)
        pred = logits.argmax(dim=1)
        correct += int((pred == y).sum().item())
        total += int(x.size(0))
    return total_loss / max(1, total), correct / max(1, total)


def train(
    model: nn.Module,
    train_loader: DataLoader,
    val_loader: DataLoader,
    device: torch.device,
    epochs: int,
    lr: float,
    weight_decay: float,
    mixed_precision: bool,
    out_dir: str,
    save_best: bool,
) -> Dict[str, Any]:
    os.makedirs(out_dir, exist_ok=True)
    criterion = nn.CrossEntropyLoss()

    params = [p for p in model.parameters() if p.requires_grad]
    optimizer = optim.AdamW(params, lr=lr, weight_decay=weight_decay)
    scaler = torch.cuda.amp.GradScaler(enabled=(mixed_precision and device.type == "cuda"))

    best_val_acc = -1.0
    history = {"train_loss": [], "val_loss": [], "val_acc": []}

    for epoch in range(1, epochs + 1):
        model.train()
        epoch_loss = 0.0
        n = 0
        for x, y in train_loader:
            x = x.to(device, non_blocking=True)
            y = y.to(device, non_blocking=True)
            optimizer.zero_grad(set_to_none=True)
            with torch.cuda.amp.autocast(enabled=(mixed_precision and device.type == "cuda")):
                logits = model(x)
                loss = criterion(logits, y)
            scaler.scale(loss).backward()
            scaler.step(optimizer)
            scaler.update()
            epoch_loss += float(loss.item()) * x.size(0)
            n += int(x.size(0))

        train_loss = epoch_loss / max(1, n)
        val_loss, val_acc = evaluate(model, val_loader, device)

        history["train_loss"].append(train_loss)
        history["val_loss"].append(val_loss)
        history["val_acc"].append(val_acc)

        ckpt = {
            "epoch": epoch,
            "model_state_dict": model.state_dict(),
            "optimizer_state_dict": optimizer.state_dict(),
            "history": history,
        }
        torch.save(ckpt, os.path.join(out_dir, "last.pt"))

        if save_best and val_acc > best_val_acc:
            best_val_acc = val_acc
            torch.save(ckpt, os.path.join(out_dir, "best.pt"))

        sys.stderr.write(
            f"Epoch {epoch}/{epochs} - train_loss={train_loss:.4f} val_loss={val_loss:.4f} val_acc={val_acc:.4f}\n"
        )
    return history


def main():
    ap = argparse.ArgumentParser(description="Download checkpoints from URLs, load with torch.load, fine-tune on dataset.")
